using System;

class Program
{
    static void Main()
    {
        Random random = new Random(42); // Sabit seed - tekrarlanabilir sonuc
        int target = random.Next(1, 101); // 1-100 arasi

        Console.WriteLine("Sayi tahmin oyunu basladi! (1-100 arasi)");
        Console.WriteLine("(Bu demo, onceden belirlenmis tahminlerle calisir)\n");

        int[] guesses = { 50, 75, 62, 68, 65, 66 };
        bool found = false;

        foreach (int guess in guesses)
        {
            Console.WriteLine("Tahmin: " + guess);

            if (guess == target)
            {
                Console.WriteLine("Tebrikler! Dogru tahmin: " + target);
                found = true;
                break;
            }
            else if (guess < target)
            {
                Console.WriteLine("Daha buyuk bir sayi dene.\n");
            }
            else
            {
                Console.WriteLine("Daha kucuk bir sayi dene.\n");
            }
        }

        if (!found)
        {
            Console.WriteLine($"\nTahmin edilemedi. Dogru sayi: {target}");
        }

        Console.WriteLine($"\nToplam deneme sayisi: {guesses.Length}");
    }
}
